45	static herr_t visit_obj_cb(hid_t obj, const char *name,
46	                            const H5O_info2_t *info, void *op_data)
47	{
48	    (void)obj;
49	    DatasetList *dl = (DatasetList *)op_data;
50	    if (info->type == H5O_TYPE_DATASET && dl->count < dl->max) {
51	        char *copy = strdup(name);
52	        if (copy)
53	            dl->names[dl->count++] = copy;
54	    }
55	    return 0; /* 0 = continue iteration */
56	}
