58	/* ------------------------------------------------------------------ */
59	/* Determine whether a type hierarchy contains VL data (needs reclaim) */
60	/* ------------------------------------------------------------------ */
61	
62	static int type_has_vlen(hid_t type_id)
63	{
64	    H5T_class_t cls = H5Tget_class(type_id);
65	    if (cls == H5T_VLEN)
66	        return 1;
67	    if (cls == H5T_STRING)
68	        return (H5Tis_variable_str(type_id) > 0);
69	    if (cls == H5T_ARRAY) {
70	        hid_t base = H5Tget_super(type_id);
71	        int   rc   = (base != H5I_INVALID_HID) ? type_has_vlen(base) : 0;
72	        if (base != H5I_INVALID_HID)
73	            H5Tclose(base);
74	        return rc;
75	    }
76	    if (cls == H5T_COMPOUND) {
77	        int n = H5Tget_nmembers(type_id);
78	        for (int i = 0; i < n; i++) {
79	            hid_t mtype = H5Tget_member_type(type_id, (unsigned)i);
80	            if (mtype == H5I_INVALID_HID)
81	                continue;
82	            int rc = type_has_vlen(mtype);
83	            H5Tclose(mtype);
84	            if (rc)
85	                return 1;
86	        }
87	    }
