95	static void read_dataset(hid_t file_id, const char *name)
96	{
97	    hid_t  dset_id   = H5I_INVALID_HID;
98	    hid_t  file_type = H5I_INVALID_HID;
99	    hid_t  mem_type  = H5I_INVALID_HID;
100	    hid_t  space_id  = H5I_INVALID_HID;
101	    void  *buf       = NULL;
102	
103	    /* Open the dataset */
104	    dset_id = H5Dopen2(file_id, name, H5P_DEFAULT);
105	    if (dset_id == H5I_INVALID_HID)
106	        goto cleanup;
107	
108	    /* Inspect the file datatype */
109	    file_type = H5Dget_type(dset_id);
110	    if (file_type == H5I_INVALID_HID)
111	        goto cleanup;
112	
113	    /* Exercise storage-size query */
114	    (void)H5Dget_storage_size(dset_id);
115	
116	    /* Get the dataspace and element count */
117	    space_id = H5Dget_space(dset_id);
118	    if (space_id == H5I_INVALID_HID)
119	        goto cleanup;
120	
121	    hssize_t npoints = H5Sget_simple_extent_npoints(space_id);
122	    if (npoints <= 0 || npoints > MAX_ELEMENTS)
123	        goto cleanup;
124	
125	    /*
126	     * Choose a memory type.
127	     * - For VL/variable-string types we copy the file type directly
128	     *   (H5Dread will allocate VL buffers that H5Treclaim must free).
129	     * - For reference types we skip entirely — reading references
130	     *   requires additional dereference context.
131	     * - For all other types we request the native platform equivalent
132	     *   (the usual real-caller pattern for integer/float/enum/compound).
133	     */
134	    H5T_class_t cls = H5Tget_class(file_type);
135	    if (cls == H5T_REFERENCE || cls == H5T_NO_CLASS)
136	        goto cleanup;
137	
138	    int has_vlen = type_has_vlen(file_type);
139	
140	    if (has_vlen) {
141	        mem_type = H5Tcopy(file_type);
142	    } else {
143	        mem_type = H5Tget_native_type(file_type, H5T_DIR_ASCEND);
144	        if (mem_type == H5I_INVALID_HID)
145	            mem_type = H5Tcopy(file_type);
146	    }
147	    if (mem_type == H5I_INVALID_HID)
148	        goto cleanup;
149	
150	    size_t type_size = H5Tget_size(mem_type);
151	    if (type_size == 0)
152	        goto cleanup;
153	
154	    /* Reject if the total allocation would be unreasonably large */
155	    size_t total_bytes = (size_t)npoints * type_size;
156	    if (total_bytes == 0 || total_bytes > MAX_MEM_BYTES)
157	        goto cleanup;
158	
159	    /*
160	     * Use calloc so that unwritten VL pointer slots are NULL — safe to
161	     * pass to H5Treclaim even if H5Dread only partially fills the buffer.
162	     */
163	    buf = calloc((size_t)npoints, type_size);
164	    if (!buf)
165	        goto cleanup;
