168	    herr_t ret = H5Dread(dset_id, mem_type, H5S_ALL, H5S_ALL,
169	                         H5P_DEFAULT, buf);
170	
171	    /* Release VL memory allocated internally by H5Dread */
172	    if (ret >= 0 && has_vlen)
173	        H5Treclaim(mem_type, space_id, H5P_DEFAULT, buf);
174	
175	cleanup:
176	    if (buf)                           free(buf);
177	    if (mem_type  != H5I_INVALID_HID)  H5Tclose(mem_type);
178	    if (file_type != H5I_INVALID_HID)  H5Tclose(file_type);
179	    if (space_id  != H5I_INVALID_HID)  H5Sclose(space_id);
180	    if (dset_id   != H5I_INVALID_HID)  H5Dclose(dset_id);
